/* ============================================
   分类管理 - 重设计
   ============================================ */

/* ---- 弹窗顶饰 ---- */
.domain-manager-accent {
  width: 48rpx;
  height: 4rpx;
  background: var(--color-accent);
  border-radius: 2rpx;
  margin: 0 auto var(--space-xl);
  opacity: 0.6;
}

/* ---- 弹窗头部 ---- */
.modal-header-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--space-xl);
}

.modal-header-row .modal-title {
  margin-bottom: 0;
}

.modal-add-btn {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  font-size: var(--text-sm);
  font-weight: 500;
  color: var(--color-accent);
  padding: var(--space-xs) var(--space-md);
  border: 1rpx solid var(--color-accent-subtle);
  border-radius: var(--radius-sm);
  background: var(--color-accent-subtle);
}

/* ---- 分类列表项（卡片式） ---- */
.domain-item {
  display: flex;
  align-items: center;
  gap: var(--space-md);
  padding: var(--space-lg) var(--space-md);
  margin-bottom: var(--space-sm);
  background: var(--color-surface);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-md);
  transition: all 0.2s;
}

.domain-item:active {
  background: var(--color-card-hover);
}

.domain-item-bar {
  width: 6rpx;
  height: 40rpx;
  border-radius: 3rpx;
  flex-shrink: 0;
}

.domain-item-icon {
  font-size: 36rpx;
  flex-shrink: 0;
  line-height: 1;
}

.domain-item-name {
  flex: 1;
  font-size: var(--text-md);
  color: var(--color-text-primary);
  font-weight: 500;
}

.domain-item-tag {
  font-size: var(--text-xs);
  color: var(--color-text-muted);
  background: var(--color-bg);
  padding: var(--space-xs) var(--space-sm);
  border-radius: var(--radius-xs);
  flex-shrink: 0;
}

.domain-item-actions {
  display: flex;
  gap: var(--space-sm);
  flex-shrink: 0;
}

.domain-item-action {
  width: 56rpx;
  height: 56rpx;
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 24rpx;
  transition: all 0.2s;
}

.domain-item-action.edit {
  background: var(--color-accent-subtle);
  color: var(--color-accent);
}

.domain-item-action.delete {
  background: var(--color-danger-subtle);
  color: var(--color-danger);
}

.domain-item-action:active {
  transform: scale(0.88);
}

.domain-item-action.disabled {
  opacity: 0.4;
}

/* ---- 弹窗关闭按钮 ---- */
.domain-close-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--space-lg) 0 var(--space-xs);
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  letter-spacing: 0.04em;
  transition: color 0.2s;
}

.domain-close-btn:active {
  color: var(--color-text-secondary);
}

/* ---- 表单区块 ---- */
.form-section {
  margin-bottom: var(--space-xl);
}

.form-section-title {
  display: block;
  font-size: var(--text-sm);
  font-weight: 500;
  color: var(--color-text-secondary);
  margin-bottom: var(--space-md);
  letter-spacing: 0.02em;
}

/* ---- Emoji 选择器（双行横滚） ---- */
.emoji-picker-rows {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.emoji-row {
  display: flex;
  gap: var(--space-sm);
  overflow-x: auto;
  overflow-y: hidden;
  padding: var(--space-xs) 0;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}

.emoji-row::-webkit-scrollbar {
  display: none;
}

.emoji-pill {
  width: 76rpx;
  height: 76rpx;
  border-radius: var(--radius-md);
  background: var(--color-surface);
  border: 1.5rpx solid var(--color-border);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 34rpx;
  flex-shrink: 0;
  transition: all 0.2s;
  box-sizing: border-box;
}

.emoji-pill:active {
  transform: scale(0.92);
  border-color: var(--color-accent);
}

.emoji-pill.selected {
  background: var(--color-accent-subtle);
  border-color: var(--color-accent);
  transform: scale(1.08);
}

/* ---- 颜色选择器（呼吸感） ---- */
.color-picker-grid {
  display: flex;
  gap: var(--space-md);
  flex-wrap: wrap;
}

.color-swatch {
  width: 68rpx;
  height: 68rpx;
  border-radius: var(--radius-full);
  border: 2rpx solid transparent;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s;
  box-sizing: border-box;
}

.color-swatch-inner {
  width: 48rpx;
  height: 48rpx;
  border-radius: var(--radius-full);
  transition: all 0.3s;
}

.color-swatch.selected {
  border-color: var(--color-accent);
  transform: scale(1.1);
}

.color-swatch.selected .color-swatch-inner {
  width: 40rpx;
  height: 40rpx;
  animation: color-breathe 2s ease-in-out infinite;
}

@keyframes color-breathe {
  0%, 100% {
    box-shadow: 0 0 12rpx 4rpx rgba(196, 132, 62, 0.25);
  }
  50% {
    box-shadow: 0 0 28rpx 10rpx rgba(196, 132, 62, 0.45);
  }
}

